package dev.harrison.rendacomcarro.attachment.application;
import java.io.*;import java.nio.file.*;import java.time.LocalDate;import java.util.UUID;import org.springframework.beans.factory.annotation.Value;import org.springframework.core.io.*;import org.springframework.stereotype.Service;
@Service public class FileStorageService {private final Path root;public FileStorageService(@Value("${app.storage.root:./var/storage}")String root){this.root=Path.of(root).toAbsolutePath().normalize();}public String store(byte[] data){try{LocalDate now=LocalDate.now();Path dir=root.resolve("attachments").resolve(String.valueOf(now.getYear())).resolve(String.format("%02d",now.getMonthValue()));Files.createDirectories(dir);String name=UUID.randomUUID().toString();Path target=dir.resolve(name).normalize();if(!target.startsWith(root))throw new InvalidAttachmentException("Caminho de armazenamento inválido");Files.write(target,data,StandardOpenOption.CREATE_NEW);return root.relativize(target).toString();}catch(IOException e){throw new IllegalStateException("Falha ao armazenar anexo",e);}}public Resource load(String relative){Path p=root.resolve(relative).normalize();if(!p.startsWith(root))throw new InvalidAttachmentException("Caminho inválido");Resource r=new FileSystemResource(p);if(!r.exists()||!r.isReadable())throw new IllegalArgumentException("Arquivo não encontrado");return r;}public void delete(String relative){try{Files.deleteIfExists(root.resolve(relative).normalize());}catch(IOException e){throw new IllegalStateException("Falha ao remover arquivo",e);}}}
